item.content:encoded:
.home #banner-inner { display: none;}

.updated-last { }

.round-box { position:relative;}
.round-box img { border-radius:50%;}
.round-box .view-btn { position:absolute; 
display:flex; top:0; justify-content:center; height:100%; align-items: center; width:100%;}
.round-box .view-btn a {border: 2px solid #fff; padding: 2px 20px;
 font-size: 18px; font-weight: 500;
 text-transform: uppercase;
 color: #fff; background: #0003; opacity:0; }
.round-box:hover .view-btn a { opacity:1;}
.cad-box .elementor-field-type-html {background: #b41e44; color: #fff!important;
padding: 3px 20px; }

.cad-box .elementor-field-type-html.elementor-field-group-field_e6a2f98 { background: transparent;
 color: #000000 !important;
 font-weight: 600; font-size: 30px;}
